            delta[i] = (0 - strategy[i]) * prices[i];
        } else {
            delta[i] = (1 - strategy[i]) * prices[i];
        }
    }

    // Now, for each window of size k, the total delta is sum of first halfK (0 - strategy) and next halfK (1 - strategy)
    // We can use sliding window to compute the maximum delta

    let currentDelta = 0;
    // Initialize the first window
    for (let i = 0; i < k; i++) {
        if (i < halfK) {
            currentDelta += (0 - strategy[i]) * prices[i];
        } else {
            currentDelta += (1 - strategy[i]) * prices[i];
        }
    }
    maxProfit = Math.max(maxProfit, originalProfit + currentDelta);

    // Slide the window
    for (let i = 1; i <= n - k; i++) {
        // Remove the leftmost element of the previous window
        const leftOut = i - 1;
        currentDelta -= (0 - strategy[leftOut]) * prices[leftOut];

