    }
    for (let i = halfK; i < k; i++) {
        currentSecondHalfOriginal += strategy[i] * prices[i];
        currentSecondHalfPrices += prices[i];
    }

    let currentDiff = -currentFirstHalfOriginal + (currentSecondHalfPrices - currentSecondHalfOriginal);
    maxProfit = Math.max(maxProfit, originalProfit + currentDiff);

    // Slide the window from 1 to n - k
    for (let i = 1; i <= n - k; i++) {
